const d = $input.first().json;
const openCount = (d.still_open ?? []).length;
const accomplishedCount = (d.accomplished ?? []).length;

let weekSummary = `Week: ${d.week_start} → ${d.week_end}\n`;
weekSummary += `Accomplished: ${accomplishedCount} item(s)\n`;

if (accomplishedCount > 0) {
  weekSummary += (d.accomplished ?? []).slice(0, 10).map(a => {
    const proj = a.project ? ` [${a.project}]` : '';
    return `  - ${a.title}${proj}`;
  }).join('\n') + '\n';
}

if ((d.decisions ?? []).length > 0) {
  weekSummary += `Decisions made: ${d.decisions.length}\n`;
  weekSummary += d.decisions.slice(0, 5).map(dc => `  - ${dc.title}`).join('\n') + '\n';
}

weekSummary += `Still open: ${openCount} task(s)\n`;
if (openCount > 0) {
  const highPri = (d.still_open ?? []).filter(t => t.priority === 'high');
  const shown = highPri.length > 0 ? highPri : (d.still_open ?? []);
  weekSummary += shown.slice(0, 10).map(t => {
    const proj = t.project ? ` [${t.project}]` : '';
    const pri = t.priority === 'high' ? ' [HIGH]' : '';
    return `  - ${t.title}${proj}${pri}`;
  }).join('\n') + '\n';
}

return [{
  json: {
    weekSummary,
    prompt: `You are a personal productivity advisor for a software engineering student.\n\nBased on this week's Second Brain activity, suggest 3-5 specific focus priorities for next week.\nBe grounded in the explicit state of open tasks and accomplishments. Do not infer completion from prose.\n\n${weekSummary}\n\nReturn numbered priorities only. No preamble.`
  }
}];

const d = $('Get Weekly Brief').first().json;
const priorities = $input.first()?.json?.candidates?.[0]?.content?.parts?.[0]?.text
  ?? '(priorities unavailable)';

const lines = [`**Second Brain – Weekly Review** | ${d.week_start} → ${d.week_end}`, ''];

if ((d.accomplished ?? []).length > 0) {
  lines.push('**Accomplished This Week**');
  (d.accomplished ?? []).forEach(a => {
    const proj = a.project ? ` \`[${a.project}]\`` : '';
    lines.push(`- ${a.title}${proj}`);
  });
  lines.push('');
}

if ((d.completed_tasks ?? []).length > 0) {
  lines.push('**Completed Tasks**');
  (d.completed_tasks ?? []).forEach(t => {
    const proj = t.project ? `[${t.project}] ` : '';
    lines.push(`- ✅ ${proj}${t.title}`);
  });
  lines.push('');
}

if ((d.decisions ?? []).length > 0) {
  lines.push('**Decisions Made**');
  (d.decisions ?? []).forEach(dc => {
    const proj = dc.project ? ` \`[${dc.project}]\`` : '';
    lines.push(`- ${dc.title}${proj}`);
  });
  lines.push('');
}

const open = d.still_open ?? [];
if (open.length > 0) {
  const shown = open.slice(0, 10);
  const extra = open.length - shown.length;
  lines.push(`**Still Open** (${open.length})`);
  shown.forEach(t => {
    const proj = t.project ? `[${t.project}] ` : '';
    const pri = t.priority === 'high' ? ' 🔴' : '';
    lines.push(`- ${proj}${t.title}${pri}`);
  });
  if (extra > 0) lines.push(`- _…and ${extra} more_`);
  lines.push('');
}

if ((d.study_progress ?? []).length > 0) {
  lines.push('**Study Progress**');
  (d.study_progress ?? []).forEach(s => lines.push(`- ${s.track}: ${s.status}`));
  lines.push('');
}

if (priorities && priorities !== '(priorities unavailable)') {
  lines.push('**🤖 AI-GENERATED PRIORITIES**');
  lines.push(priorities.trim());
  lines.push('');
} else {
  lines.push('_AI priorities unavailable this week._');
}

const total = (d.accomplished ?? []).length + (d.still_open ?? []).length;
if (total === 0) {
  lines.push('_Quiet week — nothing captured or opened. 🌱_');
}

return [{ json: { content: lines.join('\n').trim() } }];

// Weekly review delivery to Discord failed. Log safe metadata only — no capture content.
console.log(JSON.stringify({
  event: 'weekly_review_delivery_failed',
  workflow: 'second_brain_weekly_review',
  error_description: $input.first().json?.error?.description ?? 'unknown',
  error_status: $input.first().json?.error?.httpCode ?? null,
  timestamp: new Date().toISOString(),
}));
return [{ json: { recorded: true, delivery_failed: true } }];
